game_info.concept:
{
  "original_game_name": "Grand Hotel Mania\u30fb My Manager",
  "game_name": "Hotel Dash: P5 Edition",
  "genre": "Time-Management Simulation",
  "core_mechanics": "Players navigate a selection cursor across the hotel layout using keyboard controls to interact with guests, service stations, and staff. The objective is to fulfill guest needs efficiently to earn coins and maintain guest satisfaction. Guests arrive at the reception queue at timed intervals, each with a 'patience' timer. Guests display a thought bubble indicating their current need (e.g., check-in, food, room cleaning). The player must select a guest, then select the appropriate service station or staff member to assign the task. Each service has a specific duration. For example, to check in a guest, the player selects the guest, then selects an empty room. To serve food, the player selects a guest, then selects the kitchen (if Ted is free). To clean a dirty room, the player selects Monica, then selects the dirty room. If a guest's patience timer reaches zero before their need is met, they leave dissatisfied, incurring a penalty. The game tracks the current score (coins earned), number of satisfied/dissatisfied guests, and the state of all hotel entities (guests, rooms, stations, staff availability). The level timer counts down, adding pressure.",
  "visual_elements": {
    "game_objects": [
      "Hotel Layout (background, static)",
      "Reception Desk (service station)",
      "Kitchen (service station, stove icons)",
      "Rooms (5-10, with bed/door icons, indicate status)",
      "Guest Waiting Area/Paths",
      "Guests (individual characters/shapes)",
      "Staff (Ted - Chef icon, Monica - Maid icon)",
      "Selection Cursor (highlight/outline)",
      "Floating Text/Icons (coins earned, error messages)"
    ],
    "visual_representations": {
      "hotel_layout": "Top-down view, simple grid-like rooms, reception area, kitchen area. Walls and floor in muted colors (e.g., light gray, beige).",
      "reception_desk": "A rectangular counter, blue, with a small bell icon.",
      "kitchen": "A rectangular area, green, containing 1-2 stove icons (small red circles/squares).",
      "rooms": "Rectangular areas, light yellow. An un-occupied room shows a bed icon. An occupied room shows a small guest icon. A dirty room shows a 'dust cloud' icon.",
      "guest_waiting_area": "Designated path/queue lines leading to reception and then to rooms/kitchen.",
      "guests": "Simple circular or rectangular shapes (e.g., 30x40px). Varying primary colors (red, blue, green) to differentiate. Thought bubbles above their head: a bed icon for check-in, a plate icon for food, a broom icon for cleaning (if they request a room clean, which might happen if they are stuck in a dirty room temporarily). Patience bar: a horizontal bar above the guest, decreasing from green to red.",
      "staff": "Small character sprites (e.g., Ted: chef hat icon, Monica: maid uniform icon) of size similar to guests. Show 'busy' state by flashing or a small 'working' animation.",
      "selection_cursor": "A glowing, pulsating outline (e.g., bright yellow or white) that surrounds the currently selected interactive game object (guest, station, staff).",
      "ui_elements": {
        "score_display": "Text 'Score: [###]' in white, top-right corner.",
        "level_indicator": "Text 'Level: [X]' in white, directly below score.",
        "timer": "Text 'Time: [MM:SS]' in white, top-left corner.",
        "dissatisfied_guests_count": "Text 'Dissatisfied: [X]/[Y]' in white, bottom-right corner.",
        "action_prompts": "Small instructional text ('Select Target') near cursor or bottom-center."
      }
    },
    "animations_visual_effects": [
      "Guest arrival/departure (fade in/out, simple movement).",
      "Patience bar depletion (smooth color/width transition).",
      "Service station busy indicator (e.g., kitchen stove 'flames', reception bell ringing, room 'sparkles' for cleaning).",
      "Thought bubble appearance/disappearance (pop-in/fade out).",
      "Selection highlight pulse effect.",
      "Coins '+' notification when service completed (small number floats up and fades).",
      "Level transition screen (fade to black, then level complete message)."
    ]
  },
  "control_scheme": {
    "navigation": "ArrowLeft, ArrowRight, ArrowUp, ArrowDown: Moves the selection cursor between interactive game objects (guests, reception, kitchen, rooms, Ted, Monica). The cursor snaps to the nearest logical selectable entity in the direction pressed.",
    "selection_action": "Space: 'Select' the entity currently under the cursor. If no entity is selected, 'Space' selects the current entity. If a guest is selected, 'Space' on a valid service station/room assigns the task. If staff (Ted/Monica) is selected, 'Space' on a valid target (e.g., dirty room for Monica) assigns the staff member to that task. The player action state transitions between 'selectingGuest', 'selectingStaff', 'selectingTarget'.",
    "cancel_deselect": "Shift: Deselects the currently active selection, returning to a neutral selection state. This allows the player to cancel an intended action or change their mind.",
    "special_key_combinations": "None for core gameplay. 'P' for Pause/Resume (not part of main control scheme here)."
  },
  "game_states": {
    "states": [
      "START_MENU (Title screen with 'Start Game' and 'High Scores' options)",
      "PLAYING (Main game loop, active gameplay)",
      "PAUSED (Game frozen, 'Resume' and 'Main Menu' options)",
      "LEVEL_COMPLETE (Displays score, level details, 'Next Level' button)",
      "GAME_OVER (Displays final score, 'Restart' and 'Main Menu' buttons)",
      "HIGH_SCORES (Displays top scores saved in localStorage)"
    ],
    "transitions": {
      "START_MENU -> PLAYING": "Player clicks 'Start Game' button.",
      "PLAYING -> PAUSED": "Player presses 'P' key.",
      "PAUSED -> PLAYING": "Player presses 'P' key or clicks 'Resume'.",
      "PAUSED -> START_MENU": "Player clicks 'Main Menu'.",
      "PLAYING -> LEVEL_COMPLETE": "Player meets level's coin objective AND doesn't exceed dissatisfied guest limit AND level timer is still active.",
      "PLAYING -> GAME_OVER": "Player fails to meet level's coin objective when timer runs out OR exceeds dissatisfied guest limit.",
      "LEVEL_COMPLETE -> PLAYING": "Player clicks 'Next Level' button.",
      "GAME_OVER -> PLAYING": "Player clicks 'Restart' button (starts Level 1).",
      "GAME_OVER -> START_MENU": "Player clicks 'Main Menu'.",
      "START_MENU -> HIGH_SCORES": "Player clicks 'High Scores' button.",
      "HIGH_SCORES -> START_MENU": "Player clicks 'Back' button."
    }
  },
  "win_conditions": "To win a level, the player must achieve the level's target coin amount AND not exceed the maximum allowed number of dissatisfied guests, all within the given time limit. Completing the final level (Level 5) successfully wins the entire game.",
  "lose_conditions": "The player loses a level if:\n1. The level's time limit expires and the target coin amount has not been reached.\n2. The number of dissatisfied guests exceeds the maximum allowed for that level at any point.",
